/**
 * @summary Get activity logs for a patient
 */
export const getGetPatientLogsUrl = (
  patientId: string,
  params?: GetPatientLogsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/patients/${patientId}/logs?${stringifiedParams}`
    : `/api/patients/${patientId}/logs`;
};

export const getPatientLogs = async (
  patientId: string,
  params?: GetPatientLogsParams,
  options?: RequestInit,
): Promise<ActivityLog[]> => {
  return customFetch<ActivityLog[]>(getGetPatientLogsUrl(patientId, params), {
    ...options,
    method: "GET",
  });
};

export const getGetPatientLogsQueryKey = (
  patientId: string,
  params?: GetPatientLogsParams,
) => {
  return [
    `/api/patients/${patientId}/logs`,
    ...(params ? [params] : []),
  ] as const;
};

